from __future__ import annotations
import os
import time
import logging
import logging.config
from contextlib import asynccontextmanager

from fastapi import FastAPI, Depends, Request
from fastapi.exceptions import RequestValidationError
from fastapi.responses import JSONResponse
from slowapi.errors import RateLimitExceeded

from security.auth import verify_api_key
from security.rate_limiter import (limiter, rate_limit_exceeded_handler,
                                    LIMIT_DIAGNOSE, LIMIT_HEALTH, LIMIT_COMPONENTS)
from security.schemas import BlackboxDiagnoseRequest, ComponentListRequest, HealthResponse
from middleware.logging_mw import AuditLogMiddleware

logging.config.dictConfig({
    "version": 1,
    "formatters": {
        "default": {"format": "%(asctime)s %(levelname)s %(name)s %(message)s"},
    },
    "handlers": {
        "console": {"class": "logging.StreamHandler", "formatter": "default"},
    },
    "root": {"level": "INFO", "handlers": ["console"]},
})

_START_TIME: float = 0.0


@asynccontextmanager
async def lifespan(app: FastAPI):
    global _START_TIME
    _START_TIME = time.time()
    yield


app = FastAPI(
    title="音響診断API",
    version="0.1.0",
    lifespan=lifespan,
    docs_url="/docs",
    redoc_url=None,
)

app.add_middleware(AuditLogMiddleware)
app.state.limiter = limiter

app.add_exception_handler(RateLimitExceeded, rate_limit_exceeded_handler)


@app.exception_handler(RequestValidationError)
async def validation_exception_handler(request: Request, exc: RequestValidationError):
    errors = [
        {"field": ".".join(str(loc) for loc in e["loc"]), "message": e["msg"]}
        for e in exc.errors()
    ]
    return JSONResponse(
        status_code=422,
        content={"detail": "入力データが不正です", "errors": errors},
    )


@app.get("/health", response_model=HealthResponse, tags=["System"])
@limiter.limit(LIMIT_HEALTH)
async def health(request: Request) -> HealthResponse:
    """ヘルスチェック（認証不要）"""
    return HealthResponse(
        status="ok",
        version=app.version,
        uptime_seconds=time.time() - _START_TIME,
    )


@app.post("/diagnose/blackbox", tags=["Diagnosis"])
@limiter.limit(LIMIT_DIAGNOSE)
async def diagnose_blackbox(
    request: Request,
    body: BlackboxDiagnoseRequest,
    _api_key: str = Depends(verify_api_key),
) -> dict:
    """
    ブラックボックス診断エンドポイント。
    スペクトル減算 + 補正係数DBによる軸受異常診断。
    """
    from informed_nmf import diagnose_from_nmf
    from bearing_calculator import BearingFrequencyCalculator
    from signal_generator import generate_reference_signal
    from spectral_subtraction import compute_residual_spectrum
    from evaluator import detect_fault_frequencies, classify_fault
    import numpy as np

    signal = np.asarray(body.audio_samples, dtype=np.float32)
    calc = BearingFrequencyCalculator.from_jis_number(body.bearing_number, body.rpm)
    freq_map = calc.all_frequencies(harmonics=5)
    fault_map = {k: v for k, v in freq_map.items() if k in ("BPFO", "BPFI", "BSF", "FTF")}

    duration = len(signal) / body.sample_rate
    ref_signal = generate_reference_signal(freq_map, body.sample_rate, duration, rng_seed=42)

    freqs, power_residual = compute_residual_spectrum(
        signal, ref_signal, body.sample_rate, alpha=1.2
    )

    detection = detect_fault_frequencies(freqs, power_residual, fault_map)
    pred_label, confidence = classify_fault(detection)

    if pred_label == "normal":
        status = "正常"
    elif confidence < 0.5:
        status = "要確認"
    else:
        status = "異常の疑い"

    return {
        "status": status,
        "suspected_fault": pred_label if pred_label != "normal" else None,
        "confidence": round(confidence, 3),
        "fault_details": detection,
        "bearing": body.bearing_number,
        "rpm": body.rpm,
    }


@app.get("/components", tags=["Library"])
@limiter.limit(LIMIT_COMPONENTS)
async def list_components(
    request: Request,
    component_type: str = "bearing",
    _api_key: str = Depends(verify_api_key),
) -> dict:
    """コンポーネントライブラリ一覧"""
    from bearing_calculator import JIS_BEARING_DB
    if component_type == "bearing":
        return {
            "items": [
                {"id": k, "name": v.name, "nb": v.nb, "bd_mm": v.bd, "pd_mm": v.pd}
                for k, v in JIS_BEARING_DB.items()
            ]
        }
    return {"items": []}

